import React from 'react';
import './Hero.css';

export default function Hero() {
  return (
    <section className="hero" id="hero">
      <div className="section-inner hero-inner">
        <p className="hero-role hero-load hero-load-1">Video Editor &amp; Colorist</p>
        <h1 className="hero-name hero-load hero-load-2">Abhi Chakrapani</h1>
        <p className="hero-bio hero-load hero-load-3">
          I turn raw footage into stories that stop the scroll. Cinematic edits, precise cuts, and a creative eye
          - built for creators who refuse to be average.
        </p>
        <div className="hero-actions hero-load hero-load-4">
          <a className="btn btn-gradient" href="#contact">Watch Reel</a>
          <a className="btn btn-ghost" href="#work">See Work</a>
        </div>
      </div>
    </section>
  );
}
